def simplifyPath(path: str) -> str:
    stack: list[str] = []

    for part in path.split('/'):
        if part in ('', '.'):
            continue
        elif part == '..':
            if stack:
                stack.pop()
        else:
            stack.append(part)

    return '/' + '/'.join(stack)
